from flask import Flask, send_from_directory, abort
import os

app = Flask(__name__)
UPLOAD_FOLDER = 'uploads'

@app.route('/uploads/<path:filename>', methods=['GET'])
def serve_file(filename):
    legacy_filename = filename.replace('_old', '')  # Adjust for legacy naming
    file_path = os.path.join(UPLOAD_FOLDER, legacy_filename)

    if os.path.exists(file_path):
        return send_from_directory(UPLOAD_FOLDER, legacy_filename)
    
    # Check for legacy file naming
    legacy_file_path = os.path.join(UPLOAD_FOLDER, filename)
    if os.path.exists(legacy_file_path):
        return send_from_directory(UPLOAD_FOLDER, filename)

    # If file not found
    return abort(404)

if __name__ == '__main__':
    app.run(debug=True)